def solve():
    n, m = map(int, input().split())
    grid = []
    for _ in range(n):
        grid.append(input().strip())

    # prefix[i][j] = sum of grid[0..i-1][0..j-1]
    pre = [[0]*(m+1) for _ in range(n+1)]
    for i in range(n):
        for j in range(m):
            pre[i+1][j+1] = pre[i][j+1] + pre[i+1][j] - pre[i][j] + int(grid[i][j])

    def rect_sum(r1,c1,r2,c2):
        if r1>r2 or c1>c2: return 0
        return pre[r2+1][c2+1]-pre[r1][c2+1]-pre[r2+1][c1]+pre[r1][c1]

    ans = float('inf')
    for r1 in range(n-4):
        for r2 in range(r1+4, n):
            top_pre = [0]*(m+1)
            bot_pre = [0]*(m+1)
            int_pre = [0]*(m+1)
            col_cost = [0]*m
            for c in range(m):
                col_cost[c] = (r2-r1-1) - rect_sum(r1+1,c,r2-1,c)
                top_pre[c+1] = top_pre[c] + (1-int(grid[r1][c]))
                bot_pre[c+1] = bot_pre[c] + (1-int(grid[r2][c]))
                int_pre[c+1] = int_pre[c] + rect_sum(r1+1,c,r2-1,c)
            best = {}
            for c1 in range(m-3):
                val = col_cost[c1] - top_pre[c1+1] - bot_pre[c1+1] - int_pre[c1+1]
                if c1 not in best or val < best.get('v', float('inf')):
                    pass
            mn = float('inf')
            for c1 in range(m-3):
                v = col_cost[c1] - top_pre[c1+1] - bot_pre[c1+1] - int_pre[c1+1]
                c2 = c1+3
                while c2 < m:
                    cost = v + col_cost[c2] + top_pre[c2] + bot_pre[c2] + int_pre[c2]
                    if cost < ans: ans = cost
                    c2 += 1
                    break
            for c2 in range(3, m):
                mn_val = float('inf')
                for c1 in range(c2-3+1):
                    v = col_cost[c1] - top_pre[c1+1] - bot_pre[c1+1] - int_pre[c1+1]
                    if v < mn_val: mn_val = v
                cost = mn_val + col_cost[c2] + top_pre[c2] + bot_pre[c2] + int_pre[c2]
                if cost < ans: ans = cost
    print(ans)

